import { Line } from "react-chartjs-2";

const ChartArea = ({ chartData, isLoading }) => {
  const chartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: { display: false },
      tooltip: {
        mode: "index",
        intersect: false,
        backgroundColor: "rgba(255, 255, 255, 0.95)",
        titleColor: "#1f2937",
        bodyColor: "#374151",
        borderColor: "#e5e7eb",
        borderWidth: 1,
        cornerRadius: 12,
        padding: 12,
        displayColors: false,
        callbacks: {
          title: (context) => `${context[0].label}`,
          label: (context) => `₹${context.parsed.y.toLocaleString()}`,
        },
      },
    },
    scales: {
      x: {
        grid: { display: false },
        ticks: { color: "#6b7280", font: { size: 11 } },
      },
      y: {
        grid: { color: "rgba(0, 0, 0, 0.04)" },
        ticks: {
          color: "#6b7280",
          font: { size: 11 },
          callback: (value) => `₹${value.toLocaleString()}`,
        },
      },
    },
    interaction: { intersect: false, mode: "index" },
    elements: {
      point: {
        radius: 0,
        hoverRadius: 6,
        backgroundColor: "#3b82f6",
        borderColor: "#ffffff",
        borderWidth: 3,
      },
      line: { tension: 0.4 },
    },
  };

  return (
    <div className="flex-1 p-6">
      {isLoading ? (
        <div className="flex flex-col items-center justify-center h-full">
          <div className="relative mb-4">
            <div className="w-16 h-16 rounded-full border-4 border-blue-200 border-t-blue-600 animate-spin"></div>
            <div className="absolute inset-0 w-16 h-16 rounded-full border-4 border-transparent border-r-purple-300 animate-ping"></div>
          </div>
          <h3 className="text-lg font-semibold text-gray-700 mb-2">Loading Market Data</h3>
          <p className="text-gray-500 text-center">
            Fetching real-time prices and technical indicators...
          </p>
        </div>
      ) : (
        <Line data={chartData} options={chartOptions} />
      )}
    </div>
  );
};

export default ChartArea;
